import UIKit
import CoreData

class TransactionManager {
    private let context = (UIApplication.shared.delegate as! AppDelegate).persistentContainer.viewContext

    func processTransaction(amount: Double, from account: Account, to recipient: Account) {
        let transaction = Transaction(context: context)
        transaction.amount = amount
        transaction.fromAccount = account
        transaction.toAccount = recipient

        try? context.save()
    }

    func getAccountBalance(for account: Account) -> Double {
        let transactions = account.transactions?.allObjects as! [Transaction]
        return transactions.reduce(0) { $0 + $1.amount }
    }
}

class Account {
    @NSManaged var balance: Double
    @NSManaged var transactions: NSSet?
}

